// ================================================================
// BUILD THE DOCUMENT HTML
//
// This node takes the JSON your system POSTs to the webhook and
// turns it into the HTML that becomes the PDF. It supports five
// document types: invoice, quote, estimate, receipt, proforma.
//
// It is safe to edit this code. The places you are most likely
// to change are marked with:  CHANGE ME
// ================================================================


// ---- STEP 1: Get the incoming data -----------------------------
// The webhook wraps your POSTed JSON in "body". "data" also holds
// the settings from the "Workflow configuration" node.
const settings = $input.first().json;          // workflow configuration
const order = $input.first().json.body || {};  // your POSTed JSON


// ---- STEP 2: Helper that keeps the HTML safe --------------------
// Converts characters like < and & so customer-entered text cannot
// break the document layout. Wrap ANY text you print in esc(...).
function esc(text) {
  return String(text ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}


// ---- STEP 3: Document type settings ------------------------------
// Each type gets its own title, number prefix, and optional fields.
// Add your own types here if you need more.            CHANGE ME
const typeSettings = {
  invoice:  { title: 'INVOICE',          prefix: 'INV-', customerLabel: 'Bill To',       showDueDate: true,  showValidUntil: false, showPaymentMethod: false },
  quote:    { title: 'QUOTE',            prefix: 'QTE-', customerLabel: 'Quote For',     showDueDate: false, showValidUntil: true,  showPaymentMethod: false },
  estimate: { title: 'ESTIMATE',         prefix: 'EST-', customerLabel: 'Prepared For',  showDueDate: false, showValidUntil: true,  showPaymentMethod: false },
  receipt:  { title: 'RECEIPT',          prefix: 'REC-', customerLabel: 'Received From', showDueDate: false, showValidUntil: false, showPaymentMethod: true  },
  proforma: { title: 'PROFORMA INVOICE', prefix: 'PRO-', customerLabel: 'Bill To',       showDueDate: true,  showValidUntil: false, showPaymentMethod: false }
};

const docType = String(order.documentType || 'invoice').toLowerCase();
const doc = typeSettings[docType] || typeSettings.invoice;


// ---- STEP 4: Read the payload fields -----------------------------
// These names must match the JSON your system sends.    CHANGE ME
const documentNumber  = order.documentNumber || doc.prefix + Date.now();
const customerName    = order.customerName    || 'Customer';
const customerEmail   = order.customerEmail   || '';
const customerAddress = order.customerAddress || '';
const dueDate         = order.dueDate         || '';
const validUntil      = order.validUntil      || '';
const paymentMethod   = order.paymentMethod   || '';
const notes           = order.notes           || '';

// Settings from the configuration node
const companyName = settings.companyName || 'Your Company Inc.';
const logoUrl     = settings.companyLogoUrl || '';
const currency    = settings.currencySymbol || '$';
// The payload can override the default tax rate per document
const taxRate     = order.taxRate !== undefined ? Number(order.taxRate) : (Number(settings.defaultTaxRate) || 0);

// The customer email is required — the document is delivered by email
if (!customerEmail) {
  throw new Error('customerEmail is required in the payload — the ' + docType + ' is emailed to the customer.');
}


// ---- STEP 5: Read the line items ---------------------------------
// "items" must be an array like:
// [{"name":"Widget","quantity":2,"price":9.99}]
const items = Array.isArray(order.items) ? order.items : [];
if (items.length === 0) {
  throw new Error('The payload needs an items array like [{"name":"Widget","quantity":2,"price":9.99}]');
}

let itemsHtml = '';
let subtotal  = 0;
for (const item of items) {
  const quantity  = Number(item.quantity) || 0;
  const price     = Number(item.price) || 0;
  const lineTotal = quantity * price;
  subtotal = subtotal + lineTotal;
  itemsHtml = itemsHtml +
    '<tr><td>' + esc(item.name) + '</td><td>' + quantity + '</td><td>' +
    currency + price.toFixed(2) + '</td><td>' + currency + lineTotal.toFixed(2) + '</td></tr>';
}

const tax   = subtotal * taxRate;
const total = subtotal + tax;


// ---- STEP 6: Optional sections (shown only when relevant) --------
let optionalHtml = '';
if (doc.showDueDate && dueDate)             optionalHtml += '<p><strong>Due Date:</strong> ' + esc(dueDate) + '</p>';
if (doc.showValidUntil && validUntil)       optionalHtml += '<p><strong>Valid Until:</strong> ' + esc(validUntil) + '</p>';
if (doc.showPaymentMethod && paymentMethod) optionalHtml += '<p><strong>Payment Method:</strong> ' + esc(paymentMethod) + '</p>';

const logoHtml    = logoUrl ? '<img src="' + esc(logoUrl) + '" style="max-height:60px;max-width:200px;" alt="Logo">' : '';
const addressHtml = customerAddress ? '<p><strong>Address:</strong> ' + esc(customerAddress) + '</p>' : '';
const notesHtml   = notes ? '<div class="notes"><strong>Notes:</strong><br>' + esc(notes) + '</div>' : '';
const taxHtml     = taxRate > 0
  ? '<p class="right">Tax (' + (taxRate * 100).toFixed(0) + '%): ' + currency + tax.toFixed(2) + '</p>'
  : '';


// ---- STEP 7: The document itself ----------------------------------
// Normal HTML and CSS — change colors, fonts, and layout
// in the <style> block below.                          CHANGE ME
const html = `<!DOCTYPE html>
<html>
<head>
<style>
  body    { font-family: Arial, sans-serif; padding: 40px; color: #1e293b; }
  .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 24px; }
  h1      { margin: 0 0 4px 0; }
  h2      { color: #64748b; margin: 0; font-weight: 600; }
  table   { width: 100%; border-collapse: collapse; margin: 20px 0; }
  th, td  { padding: 10px; text-align: left; border-bottom: 1px solid #e2e8f0; }
  th      { background: #f1f5f9; }
  .right  { text-align: right; }
  .bold   { font-weight: bold; font-size: 18px; }
  .notes  { margin-top: 30px; padding: 15px; background: #f8fafc; border-left: 3px solid #cbd5e1; }
</style>
</head>
<body>

  <div class="header">
    <div>
      <h1>${esc(companyName)}</h1>
      <h2>${doc.title}</h2>
    </div>
    ${logoHtml}
  </div>

  <p><strong>${doc.title.charAt(0) + doc.title.slice(1).toLowerCase()} #:</strong> ${esc(documentNumber)}</p>
  <p><strong>Date:</strong> ${new Date().toISOString().slice(0, 10)}</p>
  ${optionalHtml}
  <p><strong>${doc.customerLabel}:</strong> ${esc(customerName)}</p>
  ${addressHtml}
  <p><strong>Email:</strong> ${esc(customerEmail)}</p>

  <table>
    <tr><th>Item</th><th>Qty</th><th>Price</th><th>Total</th></tr>
    ${itemsHtml}
  </table>

  <p class="right">Subtotal: ${currency}${subtotal.toFixed(2)}</p>
  ${taxHtml}
  <p class="right bold">Total: ${currency}${total.toFixed(2)}</p>

  ${notesHtml}

</body>
</html>`;


// ---- STEP 8: Hand everything to the next nodes --------------------
return [{
  json: {
    html: html,
    documentType: docType,
    documentTitle: doc.title,
    documentNumber: documentNumber,
    customerName: customerName,
    customerEmail: customerEmail,
    documentFilename: documentNumber + '.pdf',
    emailSubject: 'Your ' + docType + ' ' + documentNumber + ' from ' + companyName
  }
}];
